module k_module (
    input [2:0] x,
    output reg obf_f
);

    always @(*) begin
        case (x)
            3'b000: obf_f = 0;
            3'b001: obf_f = 1;
            3'b010: obf_f = 0;
            3'b011: obf_f = 1;
            3'b100: obf_f = 0;
            3'b101: obf_f = 1;
            3'b110: obf_f = 0;
            3'b111: obf_f = 1;
            default: obf_f = 0; // Default case
        endcase
    end
endmodule
